1	export function nextGeneration(cells: [number, number][]): [number, number][] {
2	  const key = (x: number, y: number): string => `${x},${y}`;
3	  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));
4	
5	  const countLiveNeighbors = (x: number, y: number): number => {
6	    let count = 0;
7	    for (let dx = -1; dx <= 1; dx++) {
8	      for (let dy = -1; dy <= 1; dy++) {
9	        if (dx === 0 && dy === 0) continue;
10	        if (liveSet.has(key(x + dx, y + dy))) count++;
11	      }
12	    }
13	    return count;
14	  };
15	
16	  return cells.filter(([x, y]) => {
17	    const liveNeighbors = countLiveNeighbors(x, y);
18	    return liveNeighbors === 2 || liveNeighbors === 3;
19	  });
20	}
