  const survivors = cells.filter(([x, y]) => {
    const liveNeighbors = countLiveNeighbors(x, y);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });

  const candidateSet = new Set<string>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        if (!liveSet.has(key(nx, ny))) {
          candidateSet.add(key(nx, ny));
        }
      }
    }
  }

  const births: [number, number][] = [];
  for (const k of candidateSet) {
    const [x, y] = k.split(",").map(Number) as [number, number];
    if (countLiveNeighbors(x, y) === 3) {
      births.push([x, y]);
    }
  }

  return [...survivors, ...births];
}
